{
  "content": [
    {
      "attrs": {
        "level": 1,
        "localId": "b49e93c9d071"
      },
      "content": [
        {
          "text": "Story",
          "type": "text"
        }
      ],
      "type": "heading"
    },
    {
      "attrs": {
        "localId": "5493383a9198"
      },
      "content": [
        {
          "text": "As a maintainer of RHDH plugins and also as an admin of RHDH, I expect that grouped plugins has a similar names.",
          "type": "text"
        }
      ],
      "type": "paragraph"
    },
    {
      "attrs": {
        "level": 2,
        "localId": "5f12ca6a1f58"
      },
      "content": [
        {
          "marks": [
            {
              "type": "strong"
            }
          ],
          "text": "Background",
          "type": "text"
        }
      ],
      "type": "heading"
    },
    {
      "attrs": {
        "localId": "f82d40f24ffa"
      },
      "content": [
        {
          "text": "The homepage (frontend) plugin has its name ",
          "type": "text"
        },
        {
          "marks": [
            {
              "type": "code"
            }
          ],
          "text": "dynamic-home-page",
          "type": "text"
        },
        {
          "text": " since the beginning when it was a wrapper around the Backstage ",
          "type": "text"
        },
        {
          "marks": [
            {
              "type": "code"
            }
          ],
          "text": "home",
          "type": "text"
        },
        {
          "text": " plugin add more or less just added “dynamic” mount points.",
          "type": "text"
        }
      ],
      "type": "paragraph"
    },
    {
      "attrs": {
        "localId": "3cc9681bb584"
      },
      "content": [
        {
          "text": "All moint point related code and the scalprum dependencies are not required anymore with 2.x / NFS, and can be removed.",
          "type": "text"
        }
      ],
      "type": "paragraph"
    },
    {
      "attrs": {
        "localId": "be2aaee44c16"
      },
      "content": [
        {
          "text": "With 1.10 we also added a new ",
          "type": "text"
        },
        {
          "marks": [
            {
              "type": "code"
            }
          ],
          "text": "homepage-backend",
          "type": "text"
        },
        {
          "text": ", the frontend plugin should be aligned with this naming.",
          "type": "text"
        }
      ],
      "type": "paragraph"
    },
    {
      "attrs": {
        "localId": "2b145c611b06"
      },
      "type": "paragraph"
    },
    {
      "attrs": {
        "level": 2,
        "localId": "e3ddd4db1d7a"
      },
      "content": [
        {
          "marks": [
            {
              "type": "strong"
            }
          ],
          "text": "Acceptance Criteria",
          "type": "text"
        }
      ],
      "type": "heading"
    },
    {
      "attrs": {
        "localId": "1bd0be4a29e2",
        "order": 1
      },
      "content": [
        {
          "attrs": {
            "localId": "f8142342b373"
          },
          "content": [
            {
              "attrs": {
                "localId": "c743b390b09e"
              },
              "content": [
                {
                  "text": "Remove the scalprum dependency and all related mount point code.",
                  "type": "text"
                }
              ],
              "type": "paragraph"
            }
          ],
          "type": "listItem"
        },
        {
          "attrs": {
            "localId": "0ed10591d533"
          },
          "content": [
            {
              "attrs": {
                "localId": "126aec0b92c9"
              },
              "content": [
                {
                  "text": "Rename the plugin from ",
                  "type": "text"
                },
                {
                  "marks": [
                    {
                      "type": "code"
                    }
                  ],
                  "text": "dynamic-home-page",
                  "type": "text"
                },
                {
                  "text": " to just ",
                  "type": "text"
                },
                {
                  "marks": [
                    {
                      "type": "code"
                    }
                  ],
                  "text": "homepage",
                  "type": "text"
                }
              ],
              "type": "paragraph"
            }
          ],
          "type": "listItem"
        },
        {
          "attrs": {
            "localId": "0ed10591d533"
          },
          "content": [
            {
              "attrs": {
                "localId": "8123ba8c29b4"
              },
              "content": [
                {
                  "text": "Rename the plugin id from ",
                  "type": "text"
                },
                {
                  "marks": [
                    {
                      "type": "code"
                    }
                  ],
                  "text": "home",
                  "type": "text"
                },
                {
                  "text": " to ",
                  "type": "text"
                },
                {
                  "marks": [
                    {
                      "type": "code"
                    }
                  ],
                  "text": "homepage",
                  "type": "text"
                },
                {
                  "text": " so that it can be installed parallel to the upstream home plugin",
                  "type": "text"
                }
              ],
              "type": "paragraph"
            }
          ],
          "type": "listItem"
        },
        {
          "attrs": {
            "localId": "43eab01bd8ad"
          },
          "content": [
            {
              "attrs": {
                "localId": "1a5cfd38cf29"
              },
              "content": [
                {
                  "text": "Update all overlay, catalog entities and the konflux build jobs.",
                  "type": "text"
                }
              ],
              "type": "paragraph"
            }
          ],
          "type": "listItem"
        },
        {
          "attrs": {
            "localId": "9f27ec0c2c94"
          },
          "content": [
            {
              "attrs": {
                "localId": "39c5a3d8cd25"
              },
              "content": [
                {
                  "text": "If needed, remove all OFS related test apps, unit tests and playwright tests if we have similar tests for NFS.",
                  "type": "text"
                }
              ],
              "type": "paragraph"
            }
          ],
          "type": "listItem"
        },
        {
          "attrs": {
            "localId": "9f27ec0c2c94"
          },
          "content": [
            {
              "attrs": {
                "localId": "d1a6869fe7a9"
              },
              "content": [
                {
                  "text": "Ping cope team and check if the konflux builds was updated correctly (right job names, right container image builds)",
                  "type": "text"
                }
              ],
              "type": "paragraph"
            }
          ],
          "type": "listItem"
        }
      ],
      "type": "orderedList"
    },
    {
      "attrs": {
        "localId": "5316f70f483d"
      },
      "type": "paragraph"
    },
    {
      "attrs": {
        "localId": "78c36ef4dda6"
      },
      "content": [
        {
          "text": "Since the plugin name changes this might be “a new plugin” for some components. Please double check ",
          "type": "text"
        },
        {
          "marks": [
            {
              "attrs": {
                "href": "https://gitlab.cee.redhat.com/rhidp/rhdh-plugin-catalog/-/blob/rhdh-1-rhel-9/docs/ONBOARD_KONFLUX.adoc"
              },
              "type": "link"
            }
          ],
          "text": "https://gitlab.cee.redhat.com/rhidp/rhdh-plugin-catalog/-/blob/rhdh-1-rhel-9/docs/ONBOARD_KONFLUX.adoc",
          "type": "text"
        },
        {
          "text": " and check with Nick and Karthik at the end.",
          "type": "text"
        }
      ],
      "type": "paragraph"
    },
    {
      "attrs": {
        "level": 2,
        "localId": "a65124bbb109"
      },
      "content": [
        {
          "marks": [
            {
              "type": "strong"
            }
          ],
          "text": "Dependencies and Blockers",
          "type": "text"
        }
      ],
      "type": "heading"
    },
    {
      "attrs": {
        "localId": "2b5be266820d"
      },
      "content": [
        {
          "attrs": {
            "id": "atlassian-question_mark",
            "localId": "90ee77f2c40f",
            "shortName": ":question_mark:",
            "text": ":question_mark:"
          },
          "type": "emoji"
        },
        {
          "text": " QE impacted work",
          "type": "text"
        }
      ],
      "type": "paragraph"
    },
    {
      "attrs": {
        "localId": "176934b7e049"
      },
      "content": [
        {
          "attrs": {
            "localId": "1e761a5194be"
          },
          "content": [
            {
              "attrs": {
                "localId": "6fae12d5712d"
              },
              "content": [
                {
                  "text": "Just needs to be updated",
                  "type": "text"
                }
              ],
              "type": "paragraph"
            }
          ],
          "type": "listItem"
        }
      ],
      "type": "bulletList"
    },
    {
      "attrs": {
        "localId": "3f72cc3549e2"
      },
      "content": [
        {
          "attrs": {
            "id": "atlassian-question_mark",
            "localId": "9ba5b18fd1dd",
            "shortName": ":question_mark:",
            "text": ":question_mark:"
          },
          "type": "emoji"
        },
        {
          "text": " Documentation impacted work",
          "type": "text"
        }
      ],
      "type": "paragraph"
    },
    {
      "attrs": {
        "localId": "0add2270c6b5"
      },
      "content": [
        {
          "attrs": {
            "localId": "3316bfcf2668"
          },
          "content": [
            {
              "attrs": {
                "localId": "e0ccb381e6aa"
              },
              "content": [
                {
                  "text": "Check documentation if ",
                  "type": "text"
                },
                {
                  "marks": [
                    {
                      "type": "code"
                    }
                  ],
                  "text": "dynamic-home-page",
                  "type": "text"
                },
                {
                  "text": " is refereed somewhere.",
                  "type": "text"
                }
              ],
              "type": "paragraph"
            }
          ],
          "type": "listItem"
        }
      ],
      "type": "bulletList"
    },
    {
      "attrs": {
        "level": 2,
        "localId": "b55e07f3e4c2"
