1	import { test, expect } from "@red-hat-developer-hub/e2e-test-utils/test";
2	import {
3	  LoginHelper,
4	  UIhelper,
5	} from "@red-hat-developer-hub/e2e-test-utils/helpers";
6	import { $, WorkspacePaths } from "@red-hat-developer-hub/e2e-test-utils/utils";
7	import type { BrowserContext, Page } from "@playwright/test";
8	import {
9	  DynamicHomePagePo,
10	  AVAILABLE_WIDGETS,
11	  DEFAULT_WIDGETS,
12	  HOMEPAGE_ADMIN,
13	  setupKeycloakGroups,
14	} from "../utils/dynamic-homepage";
15	
16	const DYNAMIC_HOME_PAGE_WRAPPER_DIST_NAMES: string[] = [
17	  "red-hat-developer-hub-backstage-plugin-dynamic-home-page",
18	];
19	
20	/* eslint-disable playwright/expect-expect -- assertions in DynamicHomePagePo */
21	test.describe.serial("Dynamic home page customization", () => {
22	  let context: BrowserContext | undefined;
23	  let page: Page;
24	  let uiHelper: UIhelper;
25	  let home: DynamicHomePagePo;
26	  let baseURL: string;
27	  let test1Count: number;
28	
29	  test.beforeAll(async ({ browser, rhdh }) => {
30	    test.setTimeout(10 * 60 * 1000);
31	
32	    await test.runOnce("homepage-setup", async () => {
33	      await setupKeycloakGroups();
34	
35	      const rbacConfigmapPath = WorkspacePaths.resolve(
36	        "tests/config/rbac-configmap.yaml",
37	      );
38	      const namespace = rhdh.deploymentConfig.namespace;
39	      await $`oc apply -f ${rbacConfigmapPath} -n ${namespace}`;
40	
41	      await rhdh.configure({
42	        auth: "keycloak",
43	        disableWrappers: DYNAMIC_HOME_PAGE_WRAPPER_DIST_NAMES,
44	      });
45	      await rhdh.deploy();
46	    });
47	    baseURL = rhdh.rhdhUrl;
48	    context = await browser.newContext({ baseURL });
49	    page = await context.newPage();
50	    uiHelper = new UIhelper(page);
51	    home = new DynamicHomePagePo(page, uiHelper);
52	    home.setBaseURL(baseURL);
53	  });
54	
55	  test.afterAll(async () => {
56	    await context?.close();
57	  });
58	
59	  test("Verify default widgets from server config on first load", async () => {
60	    await new LoginHelper(page).loginAsKeycloakUser();
61	    await home.resetToDefaults();
62	    await home.verifyHomePageLoaded();
63	    await home.verifyDefaultWidgetsFromConfig(DEFAULT_WIDGETS.developer);
64	  });
65	
66	  test("Verify cards display after seeding widgets", async () => {
67	    await home.seedHomePageWidgets();
68	    await home.verifyHomePageLoaded();
69	    await home.verifyAllCardsDisplayed();
70	    await home.verifyEditButtonVisible();
71	  });
72	
73	  test("Verify cards can be individually deleted in edit mode", async () => {
74	    await home.enterEditMode();
75	    await home.deleteAllCards();
76	    await home.verifyCardsDeleted();
77	  });
78	
79	  test("Verify cards can be resized in edit mode", async () => {
80	    await home.addWidget("Entity Section");
81	    await home.resizeFirstCard();
82	    await home.exitEditMode();
83	  });
84	
85	  // eslint-disable-next-line playwright/no-skipped-test -- re-enable when https://issues.redhat.com/browse/RHDHBUGS-2906 is fixed
86	  test.skip("Verify restore default cards and deleted with Clear all button", async () => {
87	    await home.restoreDefaultCards();
88	    await home.verifyCardsRestored();
89	    await home.enterEditMode();
90	    await home.clearAllCardsWithButton();
91	    await home.verifyCardsDeleted();
92	  });
93	
94	  test.describe("Plugin management", () => {
95	    test("Add widget dialog lists all available plugins", async () => {
96	      await home.enterEditMode();
97	      await home.clearAllCardsWithButton();
98	      await home.verifyAllWidgetsAvailableInDialog();
99	    });
100	
101	    test("Each widget type can be added individually", async () => {
102	      for (const widget of AVAILABLE_WIDGETS) {
103	        await home.addWidget(widget);
104	      }
105	      await home.verifyAllCardsDisplayed();
106	    });
107	
108	    test("Widgets can be removed and re-added in a single edit session", async () => {
109	      await home.clearAllCardsWithButton();
110	      await home.verifyCardsDeleted();
111	
112	      await home.addWidget("Entity Section");
113	      await home.addWidget("Recently visited");
114	      await home.exitEditMode();
115	
116	      await home.verifySpecificCardsDisplayed([
117	        "Explore Your Software Catalog",
118	        "Recently Visited",
119	      ]);
120	      await home.verifyCardNotDisplayed("Top Visited");
121	    });
122	
123	    test("Multiple widgets of the same type produce distinct cards", async () => {
124	      await home.enterEditMode();
125	      await home.clearAllCardsWithButton();
126	      await home.verifyCardsDeleted();
127	      await home.addWidget("Entity Section");
128	      await home.addWidget("Entity Section");
129	      await home.exitEditMode();
130	
131	      const cardCount = await home.getVisibleCardCount();
132	      expect(cardCount).toBe(2);
133	    });
134	
135	    test("Widget layout survives edit mode toggle", async () => {
136	      await home.enterEditMode();
137	      await home.clearAllCardsWithButton();
138	      await home.addWidget("Entity Section");
139	      await home.addWidget("Onboarding Section");
140	      await home.exitEditMode();
141	
142	      const countAfterSave = await home.getVisibleCardCount();
143	
144	      await home.enterEditMode();
145	      await home.exitEditMode();
146	
147	      const countAfterToggle = await home.getVisibleCardCount();
148	      expect(countAfterToggle).toBe(countAfterSave);
149	    });
150	  });
151	
152	  test.describe("Persistent storage", () => {
153	    test("Customizations persist across page reload", async () => {
154	      await home.seedHomePageWidgets();
155	
156	      const countBeforeReload = await home.getVisibleCardCount();
157	      expect(countBeforeReload).toBeGreaterThan(0);
158	
159	      await page.reload();
160	      await home.verifyHomePageLoaded();
161	
162	      const countAfterReload = await home.getVisibleCardCount();
163	      expect(countAfterReload).toBe(countBeforeReload);
164	      await home.verifyAllCardsDisplayed();
165	    });
166	
167	    test("Customizations persist across logout and re-login", async () => {
168	      const countBeforeLogout = await home.getVisibleCardCount();
169	      expect(countBeforeLogout).toBeGreaterThan(0);
170	
171	      await home.reloginAsKeycloakUser();
172	      await home.verifyHomePageLoaded();
173	
174	      const countAfterRelogin = await home.getVisibleCardCount();
175	      expect(countAfterRelogin).toBe(countBeforeLogout);
176	    });
177	
178	    test("Resized layout persists after reload", async () => {
179	      await home.enterEditMode();
180	      await home.clearAllCardsWithButton();
181	      await home.addWidget("Entity Section");
182	      await home.resizeFirstCard();
183	      await home.exitEditMode();
184	      const panel = page.locator('[class*="react-grid-item"]').first();
185	      const sizeBeforeReload = await panel.boundingBox();
186	      expect(sizeBeforeReload).not.toBeNull();
187	      await page.reload();
188	      await home.verifyHomePageLoaded();
189	
190	      const panelAfterReload = page
191	        .locator('[class*="react-grid-item"]')
192	        .first();
193	      const sizeAfterReload = await panelAfterReload.boundingBox();
194	      expect(sizeAfterReload).not.toBeNull();
195	
196	      expect(sizeAfterReload!.width).toBeCloseTo(sizeBeforeReload!.width, 0);
197	      expect(sizeAfterReload!.height).toBeCloseTo(sizeBeforeReload!.height, 0);
198	    });
199	
200	    test("Per-user isolation: test2 sees defaults", async () => {
201	      await home.reloginAsKeycloakUser();
202	      await home.verifyHomePageLoaded();
203	      await home.seedHomePageWidgets();
204	      test1Count = await home.getVisibleCardCount();
205	      expect(test1Count).toBe(AVAILABLE_WIDGETS.length);
206	      await home.reloginAsKeycloakUser("test2", "test2@123");
207	      await home.verifyHomePageLoaded();
208	      await home.verifyDefaultWidgetsFromConfig(DEFAULT_WIDGETS.developer);
209	    });
210	
211	    test("test2 customization does not affect test1 layout", async () => {
212	      await home.reloginAsKeycloakUser("test2", "test2@123");
213	      await home.verifyHomePageLoaded();
214	      await home.enterEditMode();
215	      await home.clearAllCardsWithButton();
216	      await home.verifyCardsDeleted();
217	      await home.reloginAsKeycloakUser();
218	      await home.verifyHomePageLoaded();
219	      const test1CountAfter = await home.getVisibleCardCount();
220	      expect(test1CountAfter).toBe(test1Count);
221	    });
222	  });
223	
224	  test.describe("Persona-based homepages", () => {
225	    test("Admin sees all group widgets", async () => {
226	      await home.reloginAsKeycloakUser(
227	        HOMEPAGE_ADMIN.username,
228	        HOMEPAGE_ADMIN.password,
229	      );
230	      await home.verifyHomePageLoaded();
231	      await home.verifyDefaultWidgetsFromConfig(DEFAULT_WIDGETS.admin);
232	    });
233	
234	    test("Developer sees developer widgets only", async () => {
235	      await home.reloginAsKeycloakUser("test2", "test2@123");
236	      await home.verifyHomePageLoaded();
237	      await home.verifyDefaultWidgetsFromConfig(DEFAULT_WIDGETS.developer);
238	      for (const widget of DEFAULT_WIDGETS.adminOnly) {
239	        await home.verifyCardNotDisplayed(widget);
240	      }
241	    });
242	
